import sys
class Solution:
    def coinChange(self, coins, targetAmount):
        if targetAmount == 0:
            return 0
        min_coins = float('inf')
        for c in coins:
            if targetAmount >= c:
                sub_coins = self.coinChange(coins, targetAmount - c)
                if sub_coins != -1:
                    min_coins = min(min_coins, sub_coins + 1)
        return min_coins if min_coins != float('inf') else -1

# driver code
