#include <bits/stdc++.h>
using namespace std;
class Solution {
public:
    int coinChange(int* coins, int coinsSize, int targetAmount) {
        if (targetAmount == 0) return 0;
        int min_coins = INT_MAX;
        for (int i = 0; i < coinsSize; i++) {
            if (targetAmount >= coins[i]) {
                int sub_coins = coinChange(coins, coinsSize, targetAmount - coins[i]);
                if (sub_coins != -1) {
                    min_coins = min(min_coins, sub_coins + 1);
                }
            }
        }
        return min_coins == INT_MAX ? -1 : min_coins;
    }
};

int main() {
    ios_base::sync_with_stdio(false);
cin.tie(NULL);
cout.tie(NULL);
    int coinsSize = 1;
    int* coins = new int[coinsSize];
    int targetAmount = 0;
    cin >> targetAmount;
    Solution s;
    cout << s.coinChange(coins, coinsSize, targetAmount) << endl;
    delete[] coins;
    return 0;
}
